{
    // Breaking change #1 – Discriminator property renamed from "Discriminator" to "$type".
    // Keeps the legacy name so existing documents and raw SQL queries
    // (e.g. SELECT * FROM c WHERE c.Discriminator = 'Blog') keep working.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // Breaking change #2 – JSON id no longer contains the discriminator prefix.
    // Existing documents have id = "Blog|<key>"; preserve that format.
    modelBuilder.Entity<Blog>().HasDiscriminatorInJsonId();

    // Breaking change #3 – Key property now maps directly to JSON id;
    // the shadow __id property was removed. Restore legacy shadow-id behaviour
    // so the key property is stored separately and __id holds the composite id.
    modelBuilder.Entity<Blog>().HasShadowId();

    // Breaking change #4 – HasIndex() now throws for Cosmos (not supported).
    // Removed the previous HasIndex(b => b.Name) call.

    // Breaking change #5 – Sync I/O is no longer supported.
    // (handled in SyncJob.cs by switching to async APIs)

    // Breaking change #6 – SQL queries must now project JSON values with VALUE.
    // Raw SQL using SELECT * is unaffected, but any scalar projections
    // (e.g. SELECT c["Name"] FROM c) must become SELECT VALUE c["Name"] FROM c.
}

